import { ImageModelV3, NoSuchModelError, ProviderV3 } from '@ai-sdk/provider';
import type { FetchFunction } from '@ai-sdk/provider-utils';
import {
  loadApiKey,
  withoutTrailingSlash,
  withUserAgentSuffix,
} from '@ai-sdk/provider-utils';
import { PixelArtImageModel } from './pixelart-image-model';
import type { PixelArtImageModelId } from './pixelart-image-settings';
import { VERSION } from './version';

export interface PixelArtProviderSettings {
  /**
   * PixelArt API key. Default value is taken from the `PIXELART_API_KEY`
   * environment variable.
   */
  apiKey?: string;

  /**
   * Base URL for the PixelArt API. Defaults to `https://api.pixelart.ai/v1`.
   */
  baseURL?: string;

  /**
   * Custom headers to include in every request.
   */
  headers?: Record<string, string>;

  /**
   * Custom fetch implementation. Useful as a middleware to intercept requests
   * or to provide a test-friendly fetch substitute.
   */
  fetch?: FetchFunction;
}

export interface PixelArtProvider extends ProviderV3 {
  /**
   * Creates a PixelArt image-generation model for the given model ID.
   */
  image(modelId: PixelArtImageModelId): ImageModelV3;

  /**
   * Creates a PixelArt image-generation model for the given model ID.
   * Alias for `image()`.
   */
  imageModel(modelId: PixelArtImageModelId): ImageModelV3;
}

const defaultBaseURL = 'https://api.pixelart.ai/v1';

/**
 * Creates a PixelArt provider instance.
 *
 * @example
 * ```ts
 * import { createPixelArt } from '@ai-sdk/pixelart';
 * import { generateImage } from 'ai';
 *
 * const pixelart = createPixelArt({ apiKey: process.env.PIXELART_API_KEY });
 *
 * const { images } = await generateImage({
 *   model: pixelart.image('pixelart-v2'),
 *   prompt: 'A pixel-art hero standing in a forest',
 *   providerOptions: {
 *     pixelart: { style: 'retro', pixelDensity: 8 },
 *   },
 * });
 * ```
 */
export function createPixelArt(
  options: PixelArtProviderSettings = {},
): PixelArtProvider {
  const baseURL = withoutTrailingSlash(options.baseURL ?? defaultBaseURL);

  const getHeaders = () =>
    withUserAgentSuffix(
      {
        Authorization: `Bearer ${loadApiKey({
          apiKey: options.apiKey,
          environmentVariableName: 'PIXELART_API_KEY',
          description: 'PixelArt',
        })}`,
        ...options.headers,
      },
      `ai-sdk/pixelart/${VERSION}`,
    );

  const createImageModel = (modelId: PixelArtImageModelId): ImageModelV3 =>
    new PixelArtImageModel(modelId, {
      provider: 'pixelart.image',
      baseURL: baseURL ?? defaultBaseURL,
      headers: getHeaders,
      fetch: options.fetch,
    });

  const throwNoLanguageModel = (modelId: string): never => {
    throw new NoSuchModelError({ modelId, modelType: 'languageModel' });
  };

  const throwNoEmbeddingModel = (modelId: string): never => {
    throw new NoSuchModelError({ modelId, modelType: 'embeddingModel' });
  };

  return {
    specificationVersion: 'v3',
    image: createImageModel,
    imageModel: createImageModel,
    languageModel: throwNoLanguageModel,
    embeddingModel: throwNoEmbeddingModel,
    textEmbeddingModel: throwNoEmbeddingModel,
  };
}

/**
 * Default PixelArt provider instance.  Uses `PIXELART_API_KEY` from the
 * environment.
 */
export const pixelart = createPixelArt();

