import { FetchFunction } from '@ai-sdk/provider-utils';
import { createTestServer } from '@ai-sdk/test-server/with-vitest';
import { describe, expect, it } from 'vitest';
import { PixelArtImageModel } from './pixelart-image-model';

const TEST_PROMPT = 'A pixel-art hero standing in a forest';

function createBasicModel({
  headers,
  fetch,
  currentDate,
}: {
  headers?: () => Record<string, string | undefined>;
  fetch?: FetchFunction;
  currentDate?: () => Date;
} = {}) {
  return new PixelArtImageModel('pixelart-v1', {
    provider: 'pixelart.image',
    baseURL: 'https://api.example.com/v1',
    headers: headers ?? (() => ({ Authorization: 'Bearer test-key' })),
    fetch,
    _internal: { currentDate },
  });
}

const TEST_IMAGE_BYTES = Buffer.from('fake-png-bytes');

describe('PixelArtImageModel', () => {
  const server = createTestServer({
    'https://api.example.com/v1/generate/pixelart-v1': {
      response: {
        type: 'json-value',
        body: {
          images: [
            {
              url: 'https://api.example.com/output/img0.png',
              width: 512,
              height: 512,
              style: 'pixel',
              pixel_density: 8,
            },
          ],
          seed: 42,
        },
      },
    },
    'https://api.example.com/output/img0.png': {
      response: {
        type: 'binary',
        body: TEST_IMAGE_BYTES,
      },
    },
  });

  describe('doGenerate', () => {
    it('sends the correct request body with prompt and n', async () => {
      const model = createBasicModel();
      await model.doGenerate({
        prompt: TEST_PROMPT,
        n: 1,
        size: undefined,
        aspectRatio: undefined,
        seed: undefined,
        providerOptions: {},
        files: undefined,
        mask: undefined,
      });

      expect(await server.calls[0].requestBodyJson).toStrictEqual({
        prompt: TEST_PROMPT,
        n: 1,
      });
    });

    it('includes size as width/height in request body', async () => {
      const model = createBasicModel();
      await model.doGenerate({
        prompt: TEST_PROMPT,
        n: 1,
        size: '256x128',
        aspectRatio: undefined,
        seed: undefined,
        providerOptions: {},
        files: undefined,
        mask: undefined,
      });

      expect(await server.calls[0].requestBodyJson).toMatchObject({
        width: 256,
        height: 128,
      });
    });

    it('includes seed when provided', async () => {
      const model = createBasicModel();
      await model.doGenerate({
        prompt: TEST_PROMPT,
        n: 1,
        size: undefined,
        aspectRatio: undefined,
        seed: 99,
        providerOptions: {},
        files: undefined,
        mask: undefined,
      });

      expect(await server.calls[0].requestBodyJson).toMatchObject({
        seed: 99,
      });
    });

    it('passes style and pixelDensity provider options', async () => {
      const model = createBasicModel();
      await model.doGenerate({
        prompt: TEST_PROMPT,
        n: 1,
        size: undefined,
        aspectRatio: undefined,
        seed: undefined,
        providerOptions: {
          pixelart: { style: 'retro', pixelDensity: 16 },
        },
        files: undefined,
        mask: undefined,
      });

      expect(await server.calls[0].requestBodyJson).toMatchObject({
        style: 'retro',
        pixel_density: 16,
      });
    });

    it('returns downloaded image bytes', async () => {
      const model = createBasicModel();
      const result = await model.doGenerate({
        prompt: TEST_PROMPT,
        n: 1,
        size: undefined,
        aspectRatio: undefined,
        seed: undefined,
        providerOptions: {},
        files: undefined,
        mask: undefined,
      });

      expect(result.images).toHaveLength(1);
      expect(result.images[0]).toEqual(new Uint8Array(TEST_IMAGE_BYTES));
    });

    it('includes providerMetadata with image details and seed', async () => {
      const model = createBasicModel();
      const result = await model.doGenerate({
        prompt: TEST_PROMPT,
        n: 1,
        size: undefined,
        aspectRatio: undefined,
        seed: undefined,
        providerOptions: {},
        files: undefined,
        mask: undefined,
      });

      expect(result.providerMetadata).toStrictEqual({
        pixelart: {
          images: [{ width: 512, height: 512, style: 'pixel', pixelDensity: 8 }],
          seed: 42,
        },
      });
    });

    it('sets the correct provider identifier', () => {
      const model = createBasicModel();
      expect(model.provider).toBe('pixelart.image');
    });

    it('uses the correct model ID', () => {
      const model = createBasicModel();
      expect(model.modelId).toBe('pixelart-v1');
    });

    it('uses the fixed timestamp from _internal.currentDate', async () => {
      const fixedDate = new Date('2024-01-01T00:00:00Z');
      const model = createBasicModel({ currentDate: () => fixedDate });
      const result = await model.doGenerate({
        prompt: TEST_PROMPT,
        n: 1,
        size: undefined,
        aspectRatio: undefined,
        seed: undefined,
        providerOptions: {},
        files: undefined,
        mask: undefined,
      });

      expect(result.response.timestamp).toEqual(fixedDate);
    });

    it('adds a warning for unparseable size strings', async () => {
      const model = createBasicModel();
      const result = await model.doGenerate({
        prompt: TEST_PROMPT,
        n: 1,
        size: 'large',
        aspectRatio: undefined,
        seed: undefined,
        providerOptions: {},
        files: undefined,
        mask: undefined,
      });

      expect(result.warnings).toContainEqual(
        expect.objectContaining({ type: 'unsupported', feature: 'size' }),
      );
    });
  });
});

