import { NoSuchModelError } from '@ai-sdk/provider';
import { describe, expect, it } from 'vitest';
import { createPixelArt, pixelart } from './pixelart-provider';
import { PixelArtImageModel } from './pixelart-image-model';

describe('createPixelArt', () => {
  it('returns a provider with specificationVersion v3', () => {
    const provider = createPixelArt({ apiKey: 'test-key' });
    expect(provider.specificationVersion).toBe('v3');
  });

  describe('image / imageModel', () => {
    it('returns a PixelArtImageModel from image()', () => {
      const provider = createPixelArt({ apiKey: 'test-key' });
      const model = provider.image('pixelart-v1');
      expect(model).toBeInstanceOf(PixelArtImageModel);
    });

    it('returns a PixelArtImageModel from imageModel()', () => {
      const provider = createPixelArt({ apiKey: 'test-key' });
      const model = provider.imageModel('pixelart-pro');
      expect(model).toBeInstanceOf(PixelArtImageModel);
    });

    it('sets the correct model ID', () => {
      const provider = createPixelArt({ apiKey: 'test-key' });
      const model = provider.image('pixelart-v2') as PixelArtImageModel;
      expect(model.modelId).toBe('pixelart-v2');
    });

    it('sets the provider identifier to pixelart.image', () => {
      const provider = createPixelArt({ apiKey: 'test-key' });
      const model = provider.image('pixelart-v1');
      expect(model.provider).toBe('pixelart.image');
    });
  });

  describe('languageModel', () => {
    it('throws NoSuchModelError', () => {
      const provider = createPixelArt({ apiKey: 'test-key' });
      expect(() => provider.languageModel('gpt-4')).toThrow(NoSuchModelError);
    });
  });

  describe('embeddingModel', () => {
    it('throws NoSuchModelError', () => {
      const provider = createPixelArt({ apiKey: 'test-key' });
      expect(() => provider.embeddingModel('text-embedding-3')).toThrow(
        NoSuchModelError,
      );
    });
  });

  describe('textEmbeddingModel', () => {
    it('throws NoSuchModelError', () => {
      const provider = createPixelArt({ apiKey: 'test-key' });
      expect(() => provider.textEmbeddingModel('text-embedding-3')).toThrow(
        NoSuchModelError,
      );
    });
  });

  describe('custom baseURL', () => {
    it('accepts a custom baseURL', () => {
      const provider = createPixelArt({
        apiKey: 'test-key',
        baseURL: 'https://my-proxy.example.com/pixelart/v1',
      });
      const model = provider.image('pixelart-v1') as PixelArtImageModel;
      // The model is constructed successfully; URL is an internal detail
      expect(model).toBeInstanceOf(PixelArtImageModel);
    });
  });
});

describe('pixelart (default instance)', () => {
  it('is a PixelArtProvider', () => {
    expect(pixelart.specificationVersion).toBe('v3');
  });
});

